import pytest
import requests

def test_create_observation_valid_loinc_code_returns_201(auth_headers, patient_id, base_url):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {
            "coding": [{
                "system": "http://loinc.org",
                "code": "8867-4",
                "display": "Heart rate"
            }]
        },
        "subject": {"reference": f"Patient/{patient_id}"}
    }
    resp = requests.post(
        f"{base_url}/Observation",
        json=payload,
        headers=auth_headers("clinician")
    )
    assert resp.status_code == 201
    body = resp.json()
    assert body.get("resourceType") == "Observation"
    assert "id" in body
    assert body["code"]["coding"][0]["system"] == "http://loinc.org"

