import pytest
import requests

def test_create_observation_duplicate_identifier_state_transition(auth_headers, patient_id, base_url):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "identifier": [{
            "system": "http://fhir-lite.example.com/identifiers",
            "value": "obs-idempotency-test-001"
        }],
        "code": {
            "coding": [{
                "system": "http://loinc.org",
                "code": "55284-4",
                "display": "Blood pressure"
            }]
        },
        "subject": {"reference": f"Patient/{patient_id}"}
    }
    headers = auth_headers("clinician")
    resp1 = requests.post(f"{base_url}/Observation", json=payload, headers=headers)
    assert resp1.status_code == 201, f"First POST expected 201, got {resp1.status_code}"
    resp2 = requests.post(f"{base_url}/Observation", json=payload, headers=headers)
    assert resp2.status_code in (200, 201, 409), (
        f"Second POST expected 200, 201, or 409, got {resp2.status_code}"
    )
    if resp2.status_code == 201:
        body1 = resp1.json()
        body2 = resp2.json()
        assert body1.get("id") == body2.get("id"), (
            "Server created duplicate resource instead of being idempotent"
        )
